import { describe, expect, it } from 'vitest';
import { ExecutionError } from '@agent-foundry/domain';
import { invalidOutputError, rateLimitError, timeoutError } from './fixtures.js';

describe('executor failure fixtures', () => {
  it('produces a timeout ExecutionError with realistic details', () => {
    const error = timeoutError();

    expect(error).toBeInstanceOf(ExecutionError);
    expect(error.message).toMatch(/timed out|timeout/i);
    expect(error.details.provider).toBeTruthy();
  });

  it('produces a rate-limit ExecutionError whose stderr carries a 429', () => {
    const error = rateLimitError();

    expect(error).toBeInstanceOf(ExecutionError);
    expect(error.details.exitCode).toBeGreaterThan(0);
    expect(error.details.stderr).toContain('429');
  });

  it('produces an invalid-output ExecutionError naming the expected artifact shape', () => {
    const error = invalidOutputError();

    expect(error).toBeInstanceOf(ExecutionError);
    expect(error.message).toContain('valid artifact JSON');
  });
});
